-- ----------------------------------------------------------------------------
-- vw_autoimmune_diseases: Target heterogeneous autoimmune disease definitions tracked across development, aging, tissues, and disease stages.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_autoimmune_diseases CASCADE;
CREATE VIEW vw_autoimmune_diseases WITH (security_invoker = ON) AS
SELECT
  t.autoimmune_disease_id,                                                      -- Stable identifier for each autoimmune disease (e.g. sle, ra, t1d).
  t.disease_label,                                                              -- Human-readable disease name.
  t.is_complex_disease,                                                         -- True when the disease is a multifactorial complex disease beyond simple monogenic traits.
  calc_autoimmune_diseases_name(t.autoimmune_disease_id) AS name,               -- Display label for the autoimmune disease.
  calc_autoimmune_diseases_relative_path(t.autoimmune_disease_id) AS relative_path,-- Canonical path to this AutoimmuneDisease page: /diseases/<slug-or-id>.
  calc_autoimmune_diseases_count_of_disease_stages(t.autoimmune_disease_id) AS count_of_disease_stages,-- Number of disease stages defined for this autoimmune disease.
  calc_autoimmune_diseases_count_of_intervention_targets(t.autoimmune_disease_id) AS count_of_intervention_targets,-- Count of validated intervention targets linked to this disease.
  t.disease_stages,                                                             -- Disease stages for this autoimmune disease.
  t.treatments,                                                                 -- Treatment histories for this disease.
  t.clinical_phenotypes,                                                        -- Clinical phenotypes observed for this disease.
  t.individual_predictions,                                                     -- Predictions of disease onset, severity, and treatment response.
  t.counterfactual_trajectories,                                                -- Counterfactual disease trajectories for this disease.
  t.intervention_targets                                                        -- Experimentally falsifiable intervention targets.
FROM autoimmune_diseases t;

-- ----------------------------------------------------------------------------
-- vw_disease_stages: Ordered disease stages capturing presymptomatic, active, remission, and treatment-refractory phases along disease progression.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_disease_stages CASCADE;
CREATE VIEW vw_disease_stages WITH (security_invoker = ON) AS
SELECT
  t.disease_stage_id,                                                           -- Stable identifier for each disease stage.
  t.stage_label,                                                                -- Human-readable stage label (e.g. presymptomatic, active).
  t.sort_order,                                                                 -- Numeric ordering of stages along disease progression.
  t.autoimmune_disease,                                                         -- Parent autoimmune disease.
  calc_disease_stages_name(t.disease_stage_id) AS name,                         -- Display label combining disease and stage.
  calc_disease_stages_parent_path(t.disease_stage_id) AS parent_path,           -- Lookup: AutoimmuneDiseases.RelativePath via AutoimmuneDisease — used to chain this entity's path under its parent.
  calc_disease_stages_relative_path(t.disease_stage_id) AS relative_path,       -- Path to this DiseaseStage page, chained under its AutoimmuneDisease parent.
  calc_disease_stages_autoimmune_disease_disease_label(t.disease_stage_id) AS autoimmune_disease_disease_label,-- Lookup of parent disease label.
  calc_disease_stages_is_presymptomatic(t.disease_stage_id) AS is_presymptomatic-- True when stage is presymptomatic diagnosis window.
FROM disease_stages t;

-- ----------------------------------------------------------------------------
-- vw_tissues: Anatomical tissues where omics assays resolve cell-state-specific effects; includes cases of missing tissues.
