  t.is_single_cell,                                                             -- True for single-cell or spatial assays resolving cellular states.
  calc_omics_modalities_name(t.omics_modality_id) AS name,                      -- Display label for the omics modality.
  calc_omics_modalities_relative_path(t.omics_modality_id) AS relative_path,    -- Canonical path to this OmicsModalitie page: /omics-modalities/<slug-or-id>.
