-- ----------------------------------------------------------------------------
-- vw_individuals: Ancestrally diverse cohort participants whose phased genomes, omics profiles, exposures, and clinical phenotypes feed causal architecture inference.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_individuals CASCADE;
CREATE VIEW vw_individuals WITH (security_invoker = ON) AS
SELECT
  t.individual_id,                                                              -- Stable identifier for each individual in the million-person cohort.
  t.given_name,                                                                 -- Participant given name (de-identified mock).
  t.family_name,                                                                -- Participant family name (de-identified mock).
  t.ancestry_label,                                                             -- Ancestry label for population stratification and ancestry-equitable risk prediction.
  t.age_years,                                                                  -- Age in years spanning development and aging windows.
  t.is_ancestry_absent_from_training,                                           -- True when individual ancestry was absent from primary training data.
  t.federated_dataset,                                                          -- Federated dataset node when enrolled via privacy-preserving federation.
  t.enrollment_date,                                                            -- Longitudinal cohort enrollment date.
  t.has_cryptic_relatedness_flag,                                               -- True when cryptic relatedness or assortative mating bias detected.
  calc_individuals_name(t.individual_id) AS name,                               -- Display name for the individual.
  calc_individuals_slug(t.individual_id) AS slug,                               -- URL slug for this case, family-given kebab (e.g. reyes-ana). Used in RelativePath.
  calc_individuals_relative_path(t.individual_id) AS relative_path,             -- Canonical path to this Individual page: /intake/new-patient/<slug-or-id>.
  calc_individuals_federated_dataset_node_label(t.individual_id) AS federated_dataset_node_label,-- Lookup of federated node label.
  calc_individuals_count_of_genomic_variants(t.individual_id) AS count_of_genomic_variants,-- Total genomic variants for rare-variant burden assessment.
  calc_individuals_count_of_causal_mechanisms(t.individual_id) AS count_of_causal_mechanisms,-- Inferred causal mechanisms linked to this individual.
  calc_individuals_count_of_epistatic_interactions(t.individual_id) AS count_of_epistatic_interactions,-- Higher-order epistasis interactions involving this individual.
  calc_individuals_rare_variant_burden_score(t.individual_id) AS rare_variant_burden_score,-- 2nd-order score from rare variant count normalized by age.
  calc_individuals_causal_architecture_score(t.individual_id) AS causal_architecture_score,-- 3rd-order composite of causal mechanisms and epistasis density.
  calc_individuals_is_development_window(t.individual_id) AS is_development_window,-- True when age falls in developmental effects window (0-25).
  calc_individuals_is_aging_window(t.individual_id) AS is_aging_window,         -- True when age falls in aging window (60+).
  calc_individuals_count_confirmed_causal_nodes(t.individual_id) AS count_confirmed_causal_nodes,-- Count of this individual's confirmed causal-architecture nodes.
  calc_individuals_sum_confirmed_causal_confidence(t.individual_id) AS sum_confirmed_causal_confidence,-- Summed confidence of this individual's confirmed causal nodes (derived causal mass).
  calc_individuals_count_cross_ancestry_confirmed_nodes(t.individual_id) AS count_cross_ancestry_confirmed_nodes,-- Confirmed nodes that also showed cross-ancestry replication.
  calc_individuals_max_severity_score(t.individual_id) AS max_severity_score,   -- Highest SeverityScore across this individual's clinical phenotypes (0 if none).
  calc_individuals_count_high_severity_phenotypes(t.individual_id) AS count_high_severity_phenotypes,-- Count of this individual's high-severity phenotypes (SeverityScore > 7).
  calc_individuals_has_high_severity_phenotype(t.individual_id) AS has_high_severity_phenotype,-- True when the individual has at least one high-severity phenotype.
  calc_individuals_count_predicted_treatment_responses(t.individual_id) AS count_predicted_treatment_responses,-- Count of this individual's treatments predicted to respond (effective ∧ mechanism-matched).
  calc_individuals_has_predicted_treatment_response(t.individual_id) AS has_predicted_treatment_response,-- True when the individual has at least one treatment predicted to respond.
  t.genomic_variants,                                                           -- Genomic variants for this individual.
  t.omics_assays,                                                               -- Omics assays for this individual.
  t.environmental_exposures,                                                    -- Longitudinal environmental exposures.
  t.treatments,                                                                 -- Treatment histories.
  t.clinical_phenotypes,                                                        -- Clinical phenotypes.
  t.causal_mechanisms,                                                          -- Inferred causal mechanisms.
  t.epistatic_interactions,                                                     -- Epistatic interactions.
  t.counterfactual_trajectories,                                                -- Counterfactual trajectories.
  t.individual_predictions,                                                     -- Individual predictions.
  t.case_narrative,                                                             -- PANEL 1 of the witness (raw leaf, read by nothing downstream): the natural-language intake case the LLM was handed. Every raw observation below is extracted from THIS text; each leaf's SourceQuote points back into it so the extraction is human-checkable independently of the verdict. Synthetic but transparent — invented case, literature-aligned loci/thresholds.
  calc_individuals_count_serology_panels(t.individual_id) AS count_serology_panels,-- Number of serology panels for this individual.
  calc_individuals_count_pre_nephritic_signature_panels(t.individual_id) AS count_pre_nephritic_signature_panels,-- How many of this individual's panels exhibit the pre-nephritic serology signature (rising anti-dsDNA + falling complement before overt nephritis). The corpus-level roll-up of the per-panel signal; emergent from the raw series.
  calc_individuals_is_in_pre_nephritic_signature_cluster(t.individual_id) AS is_in_pre_nephritic_signature_cluster,-- DERIVED cluster membership: TRUE when this individual's own raw serology series ever showed the pre-nephritic signature. The discovery 'this serology signature precedes nephritis' becomes a reproducible, witnessed corpus-level cluster — not a label anyone assigned.
  calc_individuals_signature_strength(t.individual_id) AS signature_strength,   -- DERIVED 0/1/2 strength of the pre-nephritic signature: 2 when it appears on >=2 panels (persistent), 1 on exactly one panel, 0 when absent. Drives the emphasis of cluster members on the cohort scatter.
  calc_individuals_max_progression_state_order(t.individual_id) AS max_progression_state_order,-- Highest progression-state order reached across this individual's serology panels (worst/current state).
  calc_individuals_latest_sledai_score(t.individual_id) AS latest_sledai_score, -- Peak SLEDAI activity score across this individual's panels (derived).
  calc_individuals_nephritis_progression_state_key(t.individual_id) AS nephritis_progression_state_key,-- DERIVED current disease state for the lupus-nephritis-progression machine: decoded from the highest state order reached. The subject- state column of the state machine; never hand-set.
  calc_individuals_activity_tier(t.individual_id) AS activity_tier,             -- Derived disease-activity tier from peak SLEDAI score.
  calc_individuals_is_high_disease_activity(t.individual_id) AS is_high_disease_activity,-- TRUE when peak SLEDAI >= 12.
  calc_individuals_is_disease_progressing(t.individual_id) AS is_disease_progressing,-- TRUE when the disease-state simulator places the patient in an active/worsening renal state (independent of the actionability gate).
  calc_individuals_target_pathway_code(t.individual_id) AS target_pathway_code, -- Resolved pathway code from this individual's causal mechanism (MAXIFS).
  calc_individuals_target_pathway(t.individual_id) AS target_pathway,           -- Decoded druggable pathway implicated by this individual's mechanism.
  calc_individuals_current_progression_state_id(t.individual_id) AS current_progression_state_id,-- This individual's current lupus-progression state as a MachineStates id (closure-view key form): the lupus-nephritis-progression machine prefix + the lowercased NephritisProgressionStateKey. Pure projection of the derived current state; used to look up closure-derived prognostics.
  calc_individuals_reachable_states_ahead(t.individual_id) AS reachable_states_ahead-- How many disease states are still reachable ahead of THIS patient from their current state, via the transition closure (looks up MachineStates.ReachableStateCount for CurrentProgressionStateId). A closure-derived prognostic horizon: Diego at BiopsyIndicated has 0 ahead (terminal); a Presymptomatic patient has 5. NOT derivable from the severity rank alone (the count is non-monotonic in rank because the machine branches into remission).
FROM individuals t;

-- ----------------------------------------------------------------------------
-- vw_genomic_variants: Genomic variant calls per individual spanning regulatory, coding, structural, HLA haplotypes, de novo mutations, somatic mosaicism, and mitochondrial variation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_genomic_variants CASCADE;
CREATE VIEW vw_genomic_variants WITH (security_invoker = ON) AS
SELECT
  t.genomic_variant_id,                                                         -- Stable identifier for each genomic variant record.
  t.variant_label,                                                              -- Human-readable variant label (gene/locus).
  t.individual,                                                                 -- Individual carrying this variant.
  t.variant_type,                                                               -- Variant mechanism classification.
  t.allele_frequency,                                                           -- Population allele frequency for rare-variant burden.
  t.has_allele_specific_expression,                                             -- True when allele-specific expression observed.
  calc_genomic_variants_name(t.genomic_variant_id) AS name,                     -- Display label.
  calc_genomic_variants_parent_path(t.genomic_variant_id) AS parent_path,       -- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_genomic_variants_relative_path(t.genomic_variant_id) AS relative_path,   -- Path to this GenomicVariant page, chained under its Individual parent.
  calc_genomic_variants_variant_type_label(t.genomic_variant_id) AS variant_type_label,-- Lookup of variant type label.
  calc_genomic_variants_variant_class_is_rare(t.genomic_variant_id) AS variant_class_is_rare,-- Whether this variant's class is a rare-variant class (observed type property).
  calc_genomic_variants_individual_ancestry_label(t.genomic_variant_id) AS individual_ancestry_label,-- Lookup of individual ancestry for stratification checks.
  calc_genomic_variants_is_rare_variant(t.genomic_variant_id) AS is_rare_variant,-- True when allele frequency below 0.01.
  calc_genomic_variants_is_causal_candidate(t.genomic_variant_id) AS is_causal_candidate,-- Derived: rare (by frequency or class) AND shows allele-specific expression.
  t.source_quote                                                                -- PANEL 2->1 provenance pointer (raw leaf, read by nothing downstream): the literal span of the patient's CaseNarrative from which this variant's raw value was extracted. A human verifies the EXTRACTION was faithful here, separately from trusting the derived diagnosis — which is exactly what defeats 'a hallucination laundered through a deterministic function'.
FROM genomic_variants t;

-- ----------------------------------------------------------------------------
-- vw_omics_assays: Omics assay instances linking individuals to modalities and tissues; captures batch effects, measurement error, and missing tissues.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_omics_assays CASCADE;
CREATE VIEW vw_omics_assays WITH (security_invoker = ON) AS
SELECT
  t.omics_assay_id,                                                             -- Stable identifier for each omics assay.
  t.assay_label,                                                                -- Human-readable assay label.
  t.individual,                                                                 -- Individual assayed.
  t.omics_modality,                                                             -- Omics modality used.
  t.tissue,                                                                     -- Tissue sampled; empty when missing tissues.
  t.federated_dataset,                                                          -- Source federated node if applicable.
  t.batch_id,                                                                   -- Sequencing batch for batch effects control.
  t.measurement_error_score,                                                    -- Estimated measurement error (0-1).
  t.has_cell_state_specific_effect,                                             -- True when cell-state-specific effects detected.
  calc_omics_assays_name(t.omics_assay_id) AS name,                             -- Display label.
  calc_omics_assays_parent_path(t.omics_assay_id) AS parent_path,               -- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_omics_assays_relative_path(t.omics_assay_id) AS relative_path,           -- Path to this OmicsAssay page, chained under its Individual parent.
  calc_omics_assays_modality_label(t.omics_assay_id) AS modality_label,         -- Lookup of modality label.
  calc_omics_assays_tissue_label(t.omics_assay_id) AS tissue_label,             -- Lookup of tissue label.
  calc_omics_assays_has_batch_effect_risk(t.omics_assay_id) AS has_batch_effect_risk,-- True when measurement error exceeds 0.3.
  calc_omics_assays_is_high_quality_assay(t.omics_assay_id) AS is_high_quality_assay,-- 2nd-order quality flag.
  t.evidence_items                                                              -- Evidence items measured in this assay.
FROM omics_assays t;

-- ----------------------------------------------------------------------------
-- vw_evidence_items: One observed support signal for a causal mechanism, measured by one omics assay. Mechanism confidence is an aggregation over these rows.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_evidence_items CASCADE;
CREATE VIEW vw_evidence_items WITH (security_invoker = ON) AS
SELECT
  t.evidence_item_id,                                                           -- Stable id for this evidence observation.
  t.evidence_label,                                                             -- Human label for the evidence row.
  t.causal_mechanism,                                                           -- FK to the mechanism this evidence supports.
  t.omics_assay,                                                                -- FK to the omics assay this signal was measured in.
  t.effect_size,                                                                -- OBSERVATION: measured (absolute) effect magnitude.
  t.standard_error,                                                             -- OBSERVATION: measured standard error of the effect.
  t.is_cross_modality,                                                          -- OBSERVATION: TRUE if this signal comes from a different omics modality than the mechanism's primary one.
  t.is_negative_control_arm,                                                    -- OBSERVATION: TRUE if this row is a measured control arm rather than support.
  t.is_adjusted_for_ancestry_pcs,                                               -- OBSERVATION: TRUE if the analysis adjusted for ancestry principal components.
  t.is_adjusted_for_batch,                                                      -- OBSERVATION: TRUE if the analysis adjusted for batch.
  t.is_synthetic_leaf,                                                          -- TRUST BOUNDARY (raw leaf, read by nothing downstream): TRUE marks this row as an LLM-produced synthetic-but-transparent test result rather than a real measured observation. Surfaces in the writeup so legible-reasoning-over-synthetic-evidence is never misread as solved science. The case is invented; this flag says so out loud at the cell level.
  t.represents_assay_modality,                                                  -- PROVENANCE STUB (raw leaf, read by nothing downstream): which real assay/modality this synthetic leaf stands in for (e.g. 'cis-eQTL, whole-blood RNA-seq'). Documents where real evidence would attach if this case were instrumented.
  t.identification_assumption,                                                  -- PROVENANCE STUB (raw leaf, read by nothing downstream): the identification assumption under which this leaf would be valid evidence (e.g. 'no horizontal pleiotropy; instrument relevance F>10'). Turns 'synthetic test result' into 'documentation of where real evidence attaches and under what condition it is trustworthy'.
  calc_evidence_items_name(t.evidence_item_id) AS name,                         -- Display name.
  calc_evidence_items_parent_path(t.evidence_item_id) AS parent_path,           -- Lookup: CausalMechanisms.RelativePath via CausalMechanism — used to chain this entity's path under its parent.
  calc_evidence_items_relative_path(t.evidence_item_id) AS relative_path,       -- Path to this EvidenceItem page, chained under its CausalMechanism parent.
  calc_evidence_items_assay_is_high_quality(t.evidence_item_id) AS assay_is_high_quality,-- Whether the supporting assay passed quality control.
  calc_evidence_items_z_stat(t.evidence_item_id) AS z_stat,                     -- Derived signal-to-noise ratio (effect / SE), 0 if SE non-positive.
  calc_evidence_items_is_confound_controlled(t.evidence_item_id) AS is_confound_controlled,-- Derived: both ancestry-PC and batch adjustment present.
  calc_evidence_items_is_qualified_evidence(t.evidence_item_id) AS is_qualified_evidence,-- Derived: clean assay, real support arm, signal-to-noise >= 2, confound-controlled.
  t.source_quote                                                                -- PANEL 2->1 provenance pointer (raw leaf, read by nothing downstream): the literal span of the patient's CaseNarrative from which this evidence assay's raw value was extracted. A human verifies the EXTRACTION was faithful here, separately from trusting the derived diagnosis — which is exactly what defeats 'a hallucination laundered through a deterministic function'.
FROM evidence_items t;

-- ----------------------------------------------------------------------------
-- vw_cohort_replications: One re-test of a causal mechanism in another federated cohort. Replication and cross-ancestry transport are aggregations over these rows.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_cohort_replications CASCADE;
CREATE VIEW vw_cohort_replications WITH (security_invoker = ON) AS
SELECT
  t.cohort_replication_id,                                                      -- Stable id for this replication attempt.
  t.replication_label,                                                          -- Human label.
  t.causal_mechanism,                                                           -- FK to the mechanism being re-tested.
  t.federated_dataset,                                                          -- FK to the cohort node the re-test ran in.
  t.replication_effect_sign,                                                    -- OBSERVATION: sign of the re-estimated effect (+1 / -1 / 0).
  t.replication_p_value,                                                        -- OBSERVATION: p-value of the re-test.
  t.replication_ancestry_label,                                                 -- OBSERVATION: ancestry of the cohort the re-test ran in.
  calc_cohort_replications_name(t.cohort_replication_id) AS name,               -- Display name.
  calc_cohort_replications_parent_path(t.cohort_replication_id) AS parent_path, -- Lookup: CausalMechanisms.RelativePath via CausalMechanism — used to chain this entity's path under its parent.
  calc_cohort_replications_relative_path(t.cohort_replication_id) AS relative_path,-- Path to this CohortReplication page, chained under its CausalMechanism parent.
  calc_cohort_replications_replicated_at_nominal_sig(t.cohort_replication_id) AS replicated_at_nominal_sig,-- Derived: reproduced the predicted (positive) sign at nominal significance.
  calc_cohort_replications_mechanism_primary_ancestry(t.cohort_replication_id) AS mechanism_primary_ancestry,-- Ancestry of the individual the mechanism was discovered in.
  calc_cohort_replications_is_different_ancestry_replication(t.cohort_replication_id) AS is_different_ancestry_replication,-- Derived: the re-test ran in a different ancestry than discovery.
  calc_cohort_replications_is_cross_ancestry_concordant(t.cohort_replication_id) AS is_cross_ancestry_concordant,-- Derived: replicated at significance AND in a different ancestry (the transportability atom).
  t.source_quote                                                                -- PANEL 2->1 provenance pointer (raw leaf, read by nothing downstream): the literal span of the patient's CaseNarrative from which this replication's raw value was extracted. A human verifies the EXTRACTION was faithful here, separately from trusting the derived diagnosis — which is exactly what defeats 'a hallucination laundered through a deterministic function'.
FROM cohort_replications t;

-- ----------------------------------------------------------------------------
-- vw_negative_control_tests: One stratification / permutation control on a causal mechanism. A true causal signal collapses under the control.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_negative_control_tests CASCADE;
CREATE VIEW vw_negative_control_tests WITH (security_invoker = ON) AS
SELECT
  t.negative_control_test_id,                                                   -- Stable id for this control test.
  t.control_label,                                                              -- Human label.
  t.causal_mechanism,                                                           -- FK to the mechanism being controlled.
  t.test_kind,                                                                  -- OBSERVATION: kind of control (ancestry-permutation / batch-stratified / negative-control).
  t.permutation_effect_size,                                                    -- OBSERVATION: (absolute) effect measured under the null/permuted control.
  t.null_threshold,                                                             -- OBSERVATION: pre-registered null-band half-width the control must stay within.
  calc_negative_control_tests_name(t.negative_control_test_id) AS name,         -- Display name.
  calc_negative_control_tests_parent_path(t.negative_control_test_id) AS parent_path,-- Lookup: CausalMechanisms.RelativePath via CausalMechanism — used to chain this entity's path under its parent.
  calc_negative_control_tests_relative_path(t.negative_control_test_id) AS relative_path,-- Path to this NegativeControlTest page, chained under its CausalMechanism parent.
  calc_negative_control_tests_is_survived(t.negative_control_test_id) AS is_survived,-- Derived: signal collapses under the control (within the null band), as a true causal effect should.
  t.source_quote                                                                -- PANEL 2->1 provenance pointer (raw leaf, read by nothing downstream): the literal span of the patient's CaseNarrative from which this negative control's raw value was extracted. A human verifies the EXTRACTION was faithful here, separately from trusting the derived diagnosis — which is exactly what defeats 'a hallucination laundered through a deterministic function'.
FROM negative_control_tests t;

-- ----------------------------------------------------------------------------
-- vw_environmental_exposures: Longitudinal environmental exposures contributing to gene-environment-microbiome interactions and shifting environments.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_environmental_exposures CASCADE;
CREATE VIEW vw_environmental_exposures WITH (security_invoker = ON) AS
SELECT
  t.environmental_exposure_id,                                                  -- Stable identifier for each exposure record.
  t.exposure_label,                                                             -- Exposure name (smoking, UV, particulate, etc.).
  t.individual,                                                                 -- Exposed individual.
  t.exposure_level,                                                             -- Quantified exposure intensity.
  t.exposure_start_date,                                                        -- Start of longitudinal exposure window.
  t.is_maternal_effect,                                                         -- True when exposure reflects maternal developmental effects.
  calc_environmental_exposures_name(t.environmental_exposure_id) AS name,       -- Display label.
  calc_environmental_exposures_parent_path(t.environmental_exposure_id) AS parent_path,-- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_environmental_exposures_relative_path(t.environmental_exposure_id) AS relative_path,-- Path to this EnvironmentalExposure page, chained under its Individual parent.
  calc_environmental_exposures_individual_ancestry_label(t.environmental_exposure_id) AS individual_ancestry_label,-- Ancestry lookup for stratification.
  calc_environmental_exposures_is_high_exposure(t.environmental_exposure_id) AS is_high_exposure-- True when exposure level exceeds threshold.
FROM environmental_exposures t;

-- ----------------------------------------------------------------------------
-- vw_treatments: Treatment histories capturing treatment-induced changes, treatment response, and adverse effects.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_treatments CASCADE;
CREATE VIEW vw_treatments WITH (security_invoker = ON) AS
SELECT
  t.treatment_id,                                                               -- Stable identifier for each treatment record.
  t.treatment_label,                                                            -- Therapy name.
  t.individual,                                                                 -- Treated individual.
  t.autoimmune_disease,                                                         -- Target autoimmune disease.
  t.targets_mechanism,                                                          -- FK to the CausalMechanism this treatment acts on (the drug's target mechanism). Raw leaf: which mechanism the clinician/LLM says this therapy targets.
  t.treatment_response,                                                         -- Response category: Complete, Partial, None, Adverse.
  t.has_treatment_induced_change,                                               -- True when molecular state shifted due to therapy.
  t.has_adverse_effect,                                                         -- True when adverse effects observed.
  t.start_date,                                                                 -- Treatment start date.
  calc_treatments_name(t.treatment_id) AS name,                                 -- Display label.
  calc_treatments_parent_path(t.treatment_id) AS parent_path,                   -- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_treatments_relative_path(t.treatment_id) AS relative_path,               -- Path to this Treatment page, chained under its Individual parent.
  calc_treatments_autoimmune_disease_label(t.treatment_id) AS autoimmune_disease_label,-- Disease label lookup.
  calc_treatments_is_effective_treatment(t.treatment_id) AS is_effective_treatment,-- True for Complete or Partial response without adverse effects.
  calc_treatments_is_mechanism_matched(t.treatment_id) AS is_mechanism_matched, -- True when the treatment's target mechanism is a CONFIRMED causal-architecture node (empty-guarded). This is the 'mechanism match'.
  calc_treatments_is_treatment_response_predicted(t.treatment_id) AS is_treatment_response_predicted,-- Derived: the treatment is effective AND targets a confirmed mechanism. A drug aimed at a debunked mechanism, or one that didn't respond / was adverse, is NOT predicted.
  calc_treatments_treatment_response_deciding_factor(t.treatment_id) AS treatment_response_deciding_factor-- Why response is/ isn't predicted — the single deciding reason.
FROM treatments t;

-- ----------------------------------------------------------------------------
-- vw_clinical_phenotypes: Clinical phenotypes including severity, immune dysfunction markers, and feedback from disease progression.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_clinical_phenotypes CASCADE;
CREATE VIEW vw_clinical_phenotypes WITH (security_invoker = ON) AS
SELECT
  t.clinical_phenotype_id,                                                      -- Stable identifier for each phenotype measurement.
  t.phenotype_label,                                                            -- Phenotype name.
  t.individual,                                                                 -- Individual measured.
  t.autoimmune_disease,                                                         -- Related autoimmune disease.
  t.disease_stage,                                                              -- Disease stage at measurement.
  t.tissue,                                                                     -- Tissue context if applicable.
  t.severity_score,                                                             -- Disease severity (0-10).
  t.measurement_date,                                                           -- Date of phenotype assessment.
  t.has_immune_dysfunction,                                                     -- True when immune dysfunction markers elevated.
  calc_clinical_phenotypes_name(t.clinical_phenotype_id) AS name,               -- Display label.
  calc_clinical_phenotypes_parent_path(t.clinical_phenotype_id) AS parent_path, -- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_clinical_phenotypes_relative_path(t.clinical_phenotype_id) AS relative_path,-- Path to this ClinicalPhenotype page, chained under its Individual parent.
  calc_clinical_phenotypes_disease_stage_label(t.clinical_phenotype_id) AS disease_stage_label,-- Stage label lookup.
  calc_clinical_phenotypes_is_high_severity(t.clinical_phenotype_id) AS is_high_severity,-- True when severity exceeds 7.
  calc_clinical_phenotypes_is_presymptomatic_phenotype(t.clinical_phenotype_id) AS is_presymptomatic_phenotype-- True when stage is presymptomatic.
FROM clinical_phenotypes t;

-- ----------------------------------------------------------------------------
-- vw_causal_mechanisms: Inferred causal mechanisms linking variants, exposures, and molecular state to clinical phenotypes; must be experimentally falsifiable.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_causal_mechanisms CASCADE;
CREATE VIEW vw_causal_mechanisms WITH (security_invoker = ON) AS
SELECT
  t.causal_mechanism_id,                                                        -- Stable identifier for each causal mechanism hypothesis.
  t.mechanism_label,                                                            -- Human-readable mechanism description.
  t.individual,                                                                 -- Individual for whom mechanism is inferred.
  t.genomic_variant,                                                            -- Primary genomic variant if applicable.
  t.environmental_exposure,                                                     -- Environmental exposure if gene-environment interaction.
  t.mechanism_type,                                                             -- Type: regulatory, coding, gene-environment-microbiome, epigenetic-inheritance, enhancer-promoter, feedback.
  t.target_pathway,                                                             -- NEW RAW LEAF: druggable pathway this confirmed mechanism implicates (type-I-IFN / B-cell/autoantibody / T-cell-costim / IL-17/23). Drives treatment-line selection. An observation about the mechanism, not derived.
  calc_causal_mechanisms_target_pathway_code(t.causal_mechanism_id) AS target_pathway_code,-- Numeric encoding of TargetPathway so the individual can resolve it via a MAXIFS aggregation (transpiler-friendly). 1=type-I-IFN 2=B-cell 3=T-cell 4=IL-17/23.
  t.has_pleiotropy,                                                             -- True when mechanism shows pleiotropy across phenotypes.
  calc_causal_mechanisms_name(t.causal_mechanism_id) AS name,                   -- Display label.
  calc_causal_mechanisms_parent_path(t.causal_mechanism_id) AS parent_path,     -- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_causal_mechanisms_relative_path(t.causal_mechanism_id) AS relative_path, -- Path to this CausalMechanism page, chained under its Individual parent.
  calc_causal_mechanisms_individual_ancestry_label(t.causal_mechanism_id) AS individual_ancestry_label,-- Ancestry lookup.
  calc_causal_mechanisms_count_qualified_evidence(t.causal_mechanism_id) AS count_qualified_evidence,-- Count of qualified evidence items supporting this mechanism.
  calc_causal_mechanisms_count_modalities_supporting(t.causal_mechanism_id) AS count_modalities_supporting,-- Count of qualified cross-modality evidence items (multi-omic corroboration).
  calc_causal_mechanisms_count_intervention_targets(t.causal_mechanism_id) AS count_intervention_targets,-- Count of perturbable intervention targets for this mechanism (falsifiability requires >=1).
  calc_causal_mechanisms_is_experimentally_falsifiable(t.causal_mechanism_id) AS is_experimentally_falsifiable,-- Derived: a measurable qualified effect exists AND a named intervention can perturb it.
  calc_causal_mechanisms_count_replications(t.causal_mechanism_id) AS count_replications,-- Total cross-cohort re-tests of this mechanism.
  calc_causal_mechanisms_count_concordant_replications(t.causal_mechanism_id) AS count_concordant_replications,-- Re-tests reproducing the predicted sign at significance.
  calc_causal_mechanisms_count_cross_ancestry_concordant(t.causal_mechanism_id) AS count_cross_ancestry_concordant,-- Concordant re-tests that ran in a DIFFERENT ancestry (the transportability measurement).
  calc_causal_mechanisms_replication_fraction(t.causal_mechanism_id) AS replication_fraction,-- Derived: fraction of re-tests that were concordant (guarded division).
  calc_causal_mechanisms_replicates_across_cohorts(t.causal_mechanism_id) AS replicates_across_cohorts,-- Derived: >=2 independent re-tests and >=2 concordant.
  calc_causal_mechanisms_count_neg_control_tests(t.causal_mechanism_id) AS count_neg_control_tests,-- Negative-control tests run on this mechanism.
  calc_causal_mechanisms_count_neg_control_survived(t.causal_mechanism_id) AS count_neg_control_survived,-- Negative-control tests the mechanism survived (collapsed under the null).
  calc_causal_mechanisms_survives_negative_controls(t.causal_mechanism_id) AS survives_negative_controls,-- Derived: at least one control run AND all of them survived.
  calc_causal_mechanisms_is_spurious_derived(t.causal_mechanism_id) AS is_spurious_derived,-- Derived: spurious unless replicated, survives controls, has >=2 modalities, and is not purely pleiotropic.
  calc_causal_mechanisms_causal_confidence(t.causal_mechanism_id) AS causal_confidence,-- Derived bounded blend of qualified-evidence count, modality breadth, replication rate, and control survival.
  calc_causal_mechanisms_variant_is_causal_candidate(t.causal_mechanism_id) AS variant_is_causal_candidate,-- Whether the linked variant is itself a derived causal candidate (empty-guarded).
  calc_causal_mechanisms_is_causal_architecture_node(t.causal_mechanism_id) AS is_causal_architecture_node,-- Derived: a confirmed causal edge - confident, falsifiable, non-spurious, and grounded in a candidate variant or a real exposure.
  calc_causal_mechanisms_is_ancestry_transportable(t.causal_mechanism_id) AS is_ancestry_transportable,-- Derived: a confirmed node whose effect replicated in >=1 different ancestry (measured invariance).
  t.intervention_targets,                                                       -- Intervention targets derived from this mechanism.
  t.evidence_items,                                                             -- Evidence items supporting this mechanism.
  t.cohort_replications,                                                        -- Cross-cohort replications of this mechanism.
  t.negative_control_tests                                                      -- Negative-control tests on this mechanism.
FROM causal_mechanisms t;

-- ----------------------------------------------------------------------------
-- vw_epistatic_interactions: Higher-order epistasis and pleiotropy interactions between genomic variants.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_epistatic_interactions CASCADE;
CREATE VIEW vw_epistatic_interactions WITH (security_invoker = ON) AS
SELECT
  t.epistatic_interaction_id,                                                   -- Stable identifier for each epistatic interaction.
  t.interaction_label,                                                          -- Human-readable interaction label.
  t.individual,                                                                 -- Individual exhibiting interaction.
  t.primary_variant,                                                            -- First variant in interaction.
  t.secondary_variant,                                                          -- Second variant in interaction.
  t.epistasis_score,                                                            -- Higher-order epistasis effect score (0-1).
  t.has_pleiotropy,                                                             -- True when interaction shows pleiotropy.
  calc_epistatic_interactions_name(t.epistatic_interaction_id) AS name,         -- Display label.
  calc_epistatic_interactions_parent_path(t.epistatic_interaction_id) AS parent_path,-- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_epistatic_interactions_relative_path(t.epistatic_interaction_id) AS relative_path,-- Path to this EpistaticInteraction page, chained under its Individual parent.
  calc_epistatic_interactions_is_high_order_epistasis(t.epistatic_interaction_id) AS is_high_order_epistasis-- True when epistasis score exceeds 0.5.
FROM epistatic_interactions t;

-- ----------------------------------------------------------------------------
-- vw_counterfactual_trajectories: Counterfactual disease trajectories inferred without randomized perturbation data.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_counterfactual_trajectories CASCADE;
CREATE VIEW vw_counterfactual_trajectories WITH (security_invoker = ON) AS
SELECT
  t.counterfactual_trajectory_id,                                               -- Stable identifier for each counterfactual trajectory.
  t.trajectory_label,                                                           -- Description of hypothetical scenario.
  t.individual,                                                                 -- Individual whose trajectory is modeled.
  t.autoimmune_disease,                                                         -- Target autoimmune disease.
  t.projected_severity,                                                         -- Projected severity under counterfactual (0-10).
  t.horizon_months,                                                             -- Prediction horizon in months.
  t.intervention_applied,                                                       -- Hypothetical intervention (empty = no treatment).
  calc_counterfactual_trajectories_name(t.counterfactual_trajectory_id) AS name,-- Display label.
  calc_counterfactual_trajectories_parent_path(t.counterfactual_trajectory_id) AS parent_path,-- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_counterfactual_trajectories_relative_path(t.counterfactual_trajectory_id) AS relative_path,-- Path to this CounterfactualTrajectorie page, chained under its Individual parent.
  calc_counterfactual_trajectories_autoimmune_disease_label(t.counterfactual_trajectory_id) AS autoimmune_disease_label,-- Disease label lookup.
  calc_counterfactual_trajectories_is_worsening_trajectory(t.counterfactual_trajectory_id) AS is_worsening_trajectory-- True when projected severity exceeds 7.
FROM counterfactual_trajectories t;

-- ----------------------------------------------------------------------------
-- vw_individual_predictions: Predictions of disease onset, severity, treatment response, and adverse effects with calibrated uncertainty for ancestry-equitable risk prediction.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_individual_predictions CASCADE;
CREATE VIEW vw_individual_predictions WITH (security_invoker = ON) AS
SELECT
  t.individual_prediction_id,                                                   -- Stable identifier for each prediction record.
  t.prediction_label,                                                           -- Prediction type label.
  t.individual,                                                                 -- Individual predicted.
  t.autoimmune_disease,                                                         -- Target autoimmune disease.
  t.prediction_type,                                                            -- Onset, Severity, TreatmentResponse, or AdverseEffect.
  calc_individual_predictions_name(t.individual_prediction_id) AS name,         -- Display label.
  calc_individual_predictions_parent_path(t.individual_prediction_id) AS parent_path,-- Lookup: Individuals.RelativePath via Individual — used to chain this entity's path under its parent.
  calc_individual_predictions_relative_path(t.individual_prediction_id) AS relative_path,-- Path to this IndividualPrediction page, chained under its Individual parent.
  calc_individual_predictions_individual_ancestry_label(t.individual_prediction_id) AS individual_ancestry_label,-- Ancestry for equity audit.
  calc_individual_predictions_is_ancestry_holdout(t.individual_prediction_id) AS is_ancestry_holdout,-- True when individual ancestry absent from training.
  calc_individual_predictions_individual_causal_mass(t.individual_prediction_id) AS individual_causal_mass,-- Summed confirmed causal confidence for this individual (empty-guarded).
  calc_individual_predictions_individual_confirmed_node_count(t.individual_prediction_id) AS individual_confirmed_node_count,-- Count of this individual's confirmed causal nodes (empty-guarded).
  calc_individual_predictions_individual_cross_ancestry_node_coun(t.individual_prediction_id) AS individual_cross_ancestry_node_count,-- Count of this individual's cross-ancestry-replicated confirmed nodes (empty-guarded).
  calc_individual_predictions_individual_has_cryptic_relatedness(t.individual_prediction_id) AS individual_has_cryptic_relatedness,-- Whether this individual carries a cryptic-relatedness leakage flag (empty-guarded).
  calc_individual_predictions_individual_max_severity_score(t.individual_prediction_id) AS individual_max_severity_score,-- This individual's max clinical SeverityScore (empty-guarded).
  calc_individual_predictions_individual_has_high_severity_phenot(t.individual_prediction_id) AS individual_has_high_severity_phenotype,-- Whether this individual has a high-severity phenotype (empty-guarded).
  calc_individual_predictions_individual_has_predicted_treatment_(t.individual_prediction_id) AS individual_has_predicted_treatment_response,-- Whether this individual has a treatment predicted to respond (empty-guarded).
  calc_individual_predictions_predicted_value(t.individual_prediction_id) AS predicted_value,-- Derived risk magnitude (0-10), a monotone function of validated causal mass only - rides mechanism, not ancestry correlation.
  calc_individual_predictions_count_bins(t.individual_prediction_id) AS count_bins,-- Total reliability bins for this prediction.
  calc_individual_predictions_count_well_calibrated_bins(t.individual_prediction_id) AS count_well_calibrated_bins,-- Bins passing coverage and accuracy.
  calc_individual_predictions_sum_bin_abs_error(t.individual_prediction_id) AS sum_bin_abs_error,-- Summed reliability gap across this prediction's bins.
  calc_individual_predictions_mean_bin_abs_error(t.individual_prediction_id) AS mean_bin_abs_error,-- Derived mean reliability gap; defaults to 1 (worst) when no bins exist.
  calc_individual_predictions_well_calibrated_fraction(t.individual_prediction_id) AS well_calibrated_fraction,-- Derived fraction of trustworthy bins (guarded division).
  calc_individual_predictions_calibrated_uncertainty(t.individual_prediction_id) AS calibrated_uncertainty,-- Derived reliability (HIGH = trustworthy): (1 - mean gap) scaled by well-covered-bin fraction; 0 for uncovered predictions.
  calc_individual_predictions_rests_on_confirmed_mechanism(t.individual_prediction_id) AS rests_on_confirmed_mechanism,-- Derived: grounded in >=1 validated mechanism.
  calc_individual_predictions_has_spurious_correlation_flag(t.individual_prediction_id) AS has_spurious_correlation_flag,-- Derived: spurious if no validated mechanism OR cryptic-relatedness leakage.
  calc_individual_predictions_is_falsifiability_backed(t.individual_prediction_id) AS is_falsifiability_backed,-- Derived: inherits falsifiability - every confirmed node required IsExperimentallyFalsifiable.
  calc_individual_predictions_is_transportable_to_absent_ancestry(t.individual_prediction_id) AS is_transportable_to_absent_ancestry,-- Derived: a holdout individual is transportable only with >=1 cross-ancestry-replicated node and no spurious flag.
  calc_individual_predictions_is_ancestry_transport_safe(t.individual_prediction_id) AS is_ancestry_transport_safe,-- Derived: holdout requires measured transport; in-training is vacuously safe.
  calc_individual_predictions_transport_gate_status(t.individual_prediction_id) AS transport_gate_status,-- RENDER ONLY (does NOT feed the keystone): honest three-state view of the transport gate so a vacuous in-training pass is never shown as evidentiary. NotApplicable = in-training ancestry (gate did not bite); PASS-tested = holdout with a confirmed cross-ancestry transport; FAIL = holdout without one. Sits beside IsAncestryTransportSafe (which the keystone still reads) purely to keep the writeup from implying transport evidence it never used.
  calc_individual_predictions_is_high_confidence_prediction(t.individual_prediction_id) AS is_high_confidence_prediction,-- Derived: calibrated AND not spurious.
  calc_individual_predictions_patient_stratification_tier(t.individual_prediction_id) AS patient_stratification_tier,-- Derived risk tier from the derived PredictedValue.
  calc_individual_predictions_predicted_severity_value(t.individual_prediction_id) AS predicted_severity_value,-- Derived severity prediction grounded in the individual's max clinical SeverityScore.
  calc_individual_predictions_severity_tier(t.individual_prediction_id) AS severity_tier,-- Derived severity band from the predicted severity value.
  calc_individual_predictions_is_severity_actionable(t.individual_prediction_id) AS is_severity_actionable,-- Derived: a high-severity phenotype on a confirmed, non-spurious mechanism. Chained to the onset gates so severity can never be actionable on a debunked mechanism.
  calc_individual_predictions_severity_deciding_factor(t.individual_prediction_id) AS severity_deciding_factor,-- Why severity is/ isn't actionable — the single deciding reason.
  calc_individual_predictions_is_treatment_response_actionable(t.individual_prediction_id) AS is_treatment_response_actionable,-- Derived: the individual has a treatment predicted to respond (effective therapy on a confirmed mechanism). The third prediction type — independent of onset/severity.
  calc_individual_predictions_treatment_response_deciding_factor(t.individual_prediction_id) AS treatment_response_deciding_factor,-- Why treatment-response is/ isn't actionable for this individual.
  calc_individual_predictions_is_clinically_actionable(t.individual_prediction_id) AS is_clinically_actionable,-- KEYSTONE: TRUE only when the prediction is high-confidence (calibrated + not spurious), falsifiability-backed, ancestry-transport-safe, and rests on a non-null derived magnitude.
  calc_individual_predictions_lifecycle_state_key(t.individual_prediction_id) AS lifecycle_state_key,-- DERIVED current lifecycle state (never entered): the single deciding gate determines whether the case lands on Actionable or NotActionable. Subject-state column of the diagnosis-lifecycle machine.
  calc_individual_predictions_deciding_gate(t.individual_prediction_id) AS deciding_gate,-- DERIVED single primary deciding gate (never entered), named in keystone-AND priority order. 'AllGatesPass' when actionable. When the case rests on no validated mechanism (no confirmed causal node), Falsifiability, Confidence, and Magnitude are one and the same finding, reported as 'NoValidatedMechanism' rather than split across three gates. Otherwise the lone failing gate is named: CrypticRelatedness, Calibration, AncestryTransport.
  t.calibration_bins,                                                           -- Reliability bins for this prediction.
  calc_individual_predictions_individual_target_pathway(t.individual_prediction_id) AS individual_target_pathway,-- TargetPathway resolved on the individual (decoded from the mechanism).
  calc_individual_predictions_individual_progression_state_key(t.individual_prediction_id) AS individual_progression_state_key,-- Lookup: the individual's derived disease state.
  calc_individual_predictions_individual_is_disease_progressing(t.individual_prediction_id) AS individual_is_disease_progressing,-- Lookup: is the individual's disease progressing (simulator).
  calc_individual_predictions_recommended_treatment_line(t.individual_prediction_id) AS recommended_treatment_line,-- DERIVED treatment-line recommendation from confirmed-mechanism TargetPathway + disease state. The audit's MMF/belimumab/anifrolumab example.
  calc_individual_predictions_treatment_line_deciding_factor(t.individual_prediction_id) AS treatment_line_deciding_factor,-- The single deciding reason for the recommended line (mirrors DecidingGate style).
  calc_individual_predictions_progression_vs_actionability_disagr(t.individual_prediction_id) AS progression_vs_actionability_disagree-- THE COUNTER-EXAMPLE FLAG: TRUE when disease is progressing (simulator) but the prediction is NOT clinically actionable (gate). Proves the two layers are independent.
FROM individual_predictions t;

-- ----------------------------------------------------------------------------
-- vw_calibration_bins: Per-prediction reliability-curve bins, seeded from the held-out coverage of this individual's own ancestry x disease. Calibration is an aggregation over these rows.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_calibration_bins CASCADE;
CREATE VIEW vw_calibration_bins WITH (security_invoker = ON) AS
SELECT
  t.calibration_bin_id,                                                         -- Stable id for this bin.
  t.bin_label,                                                                  -- Human label.
  t.individual_prediction,                                                      -- FK to the prediction this bin calibrates.
  t.predicted_probability_band,                                                 -- OBSERVATION: predicted-probability midpoint of this bin (0-1).
  t.observed_event_rate,                                                        -- OBSERVATION: empirical event rate among held-out cases in this band, matched to this individual's ancestry x disease.
  t.coverage_count,                                                             -- OBSERVATION: number of held-out outcomes in this band for this ancestry x disease.
  calc_calibration_bins_name(t.calibration_bin_id) AS name,                     -- Display name.
  calc_calibration_bins_parent_path(t.calibration_bin_id) AS parent_path,       -- Lookup: IndividualPredictions.RelativePath via IndividualPrediction — used to chain this entity's path under its parent.
  calc_calibration_bins_relative_path(t.calibration_bin_id) AS relative_path,   -- Path to this CalibrationBin page, chained under its IndividualPrediction parent.
  calc_calibration_bins_bin_abs_error(t.calibration_bin_id) AS bin_abs_error,   -- Derived: absolute gap between predicted band and observed rate.
  calc_calibration_bins_is_well_calibrated_bin(t.calibration_bin_id) AS is_well_calibrated_bin,-- Derived: enough held-out coverage AND small reliability gap.
  t.source_quote                                                                -- PANEL 2->1 provenance pointer (raw leaf, read by nothing downstream): the literal span of the patient's CaseNarrative from which this calibration bin's raw value was extracted. A human verifies the EXTRACTION was faithful here, separately from trusting the derived diagnosis — which is exactly what defeats 'a hallucination laundered through a deterministic function'.
FROM calibration_bins t;

-- ----------------------------------------------------------------------------
-- vw_intervention_targets: Validated intervention targets for gene-based and cell-based therapies derived from falsifiable causal mechanisms.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_intervention_targets CASCADE;
CREATE VIEW vw_intervention_targets WITH (security_invoker = ON) AS
SELECT
  t.intervention_target_id,                                                     -- Stable identifier for each intervention target.
  t.target_label,                                                               -- Target name (gene, pathway, cell type).
  t.causal_mechanism,                                                           -- Parent causal mechanism.
  t.autoimmune_disease,                                                         -- Target autoimmune disease.
  t.therapy_class,                                                              -- Gene-based, Cell-based, or Environmental.
  t.is_validated,                                                               -- True when target is validated for clinical trials.
  calc_intervention_targets_name(t.intervention_target_id) AS name,             -- Display label.
  calc_intervention_targets_parent_path(t.intervention_target_id) AS parent_path,-- Lookup: CausalMechanisms.RelativePath via CausalMechanism — used to chain this entity's path under its parent.
  calc_intervention_targets_relative_path(t.intervention_target_id) AS relative_path,-- Path to this InterventionTarget page, chained under its CausalMechanism parent.
  calc_intervention_targets_causal_mechanism_label(t.intervention_target_id) AS causal_mechanism_label,-- Mechanism label lookup.
  calc_intervention_targets_is_gene_based_therapy(t.intervention_target_id) AS is_gene_based_therapy,-- True when therapy class is gene-based.
  calc_intervention_targets_is_cell_based_therapy(t.intervention_target_id) AS is_cell_based_therapy-- True when therapy class is cell-based.
FROM intervention_targets t;

-- ----------------------------------------------------------------------------
-- vw_axioms: Non-negotiable invariants the platform must obey. Load-bearing constraints, not per-loop work. Captured from the gauntlet conversation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_axioms CASCADE;
CREATE VIEW vw_axioms WITH (security_invoker = ON) AS
SELECT
  t.axiom_id,                                                                   -- Stable identifier for the axiom.
  t.statement,                                                                  -- The invariant, stated as a rule.
  t.rationale,                                                                  -- Why this must hold / what it defends against.
  t.category,                                                                   -- Grouping: trust-boundary | solve-by-inference | knob | witness | scope | report-derivation.
  calc_axioms_name(t.axiom_id) AS name,                                         -- Display label.
  calc_axioms_relative_path(t.axiom_id) AS relative_path                        -- Path to this Axioms entry: /admin/axioms/<id>.
FROM axioms t;

-- ----------------------------------------------------------------------------
-- vw_tests_for_success: Falsifiable conditions that prove the axioms hold. The human-readable index of what each demonstration shows; many are realized in the witnessed harness.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_tests_for_success CASCADE;
CREATE VIEW vw_tests_for_success WITH (security_invoker = ON) AS
SELECT
  t.test_for_success_id,                                                        -- Stable identifier.
  t.claim,                                                                      -- The success condition, stated falsifiably.
  t.how_witnessed,                                                              -- How a human/expert confirms it without trusting the code.
  t.related_harness_file,                                                       -- Harness file that realizes it, if any.
  t.status,                                                                     -- red | green | planned.
  calc_tests_for_success_name(t.test_for_success_id) AS name,                   -- Display label.
  calc_tests_for_success_relative_path(t.test_for_success_id) AS relative_path  -- Path to this TestsForSuccess entry: /admin/tests-for-success/<id>.
FROM tests_for_success t;

-- ----------------------------------------------------------------------------
-- vw_features: Catalog of buildable capabilities the platform has / allows for. Coarser grain than loops. Each row carries challenge provenance (ChallengeRefs: exact quoted text + file/line/col into THE-ORIGINAL-CHALLENGE.md, for UI hover tips), a Category, a Priority, and a free-form Markdown ChallengeNotes comment. Source of truth for the DERIVED PLATFORM_FEATURES.md. AssignedLoop links a feature to the loop that delivers it (nullable until scheduled).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_features CASCADE;
CREATE VIEW vw_features WITH (security_invoker = ON) AS
SELECT
  t.feature_id,                                                                 -- Stable identifier.
  t.title,                                                                      -- Short feature name.
  t.category,                                                                   -- Which layer of the platform this belongs to (Keystone / inference DAG, Leaf / LLM surface, Witness / harness, Disease-state simulation, Treatment reasoning, Corpus-level discovery, Reporting, Platform infrastructure).
  t.priority,                                                                   -- Load-bearing | Supporting | Roadmap.
  t.description,                                                                -- What the capability does (factual, not a pitch).
  t.challenge_refs,                                                             -- JSON array of provenance pointers into THE-ORIGINAL-CHALLENGE.md. Each: {file,line,col,len,quote,section,relation}. col is the 0-based char offset within the line; len is the quote length; section is prompt|payoff|audit|response; relation is direct|indirect. Drives UI hover tips that highlight the exact span.
  t.challenge_refs_rendered,                                                    -- Pre-flattened Markdown bullet list of ChallengeRefs, so the dumb hbars template can print it verbatim (the engine has no loop-over-JSON helper).
  t.challenge_notes,                                                            -- Free-form Markdown comment: which challenge elements this relates to (directly or indirectly) and how it is load-bearing or illustrative.
  t.ref_count,                                                                  -- Number of challenge refs (carried as raw for display; the hbars engine can't count a JSON string).
  t.assigned_loop,                                                              -- FK -> LeopoldLoops.LeopoldLoopId; empty if unscheduled.
  calc_features_name(t.feature_id) AS name,                                     -- Display label.
  calc_features_relative_path(t.feature_id) AS relative_path,                   -- Path to this Features entry: /admin/features/<id>.
  calc_features_meta_line(t.feature_id) AS meta_line                            -- One-line meta summary for the catalog (category - priority - ref count).
FROM features t;

-- ----------------------------------------------------------------------------
-- vw_inference_kinds: Families of derivation the platform performs - the KINDS of inference in the DAG (lookups, aggregations, higher-order gates, state machines, transitive closure, predicate-gated narrative, cross-substrate conformance), independent of any one feature. Lets PLATFORM_FEATURES.md open with a short overview of the reasoning machinery before the per-feature catalog. Grounded in field types that actually exist in this rulebook; Maturity is Live unless an upstream step is still in flight.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_inference_kinds CASCADE;
CREATE VIEW vw_inference_kinds WITH (security_invoker = ON) AS
SELECT
  t.inference_kind_id,                                                          -- Stable identifier.
  t.title,                                                                      -- Short name of the inference family.
  t.description,                                                                -- One-line factual description of the kind.
  t.example_field,                                                              -- A concrete field in the model that realizes this kind.
  t.evidence_count,                                                             -- How much of it exists (field counts / usage), for honest weight.
  t.maturity,                                                                   -- Live | Partial (Partial = an upstream step is still in flight).
  t.sort_order,                                                                 -- Display order in the overview.
  calc_inference_kinds_name(t.inference_kind_id) AS name,                       -- Display label.
  calc_inference_kinds_relative_path(t.inference_kind_id) AS relative_path      -- Path to this entry: /admin/inference-kinds/<id>.
FROM inference_kinds t;

-- ----------------------------------------------------------------------------
-- vw_open_questions: Decisions still pending, captured so they are not silently re-litigated in a later session.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_open_questions CASCADE;
CREATE VIEW vw_open_questions WITH (security_invoker = ON) AS
SELECT
  t.open_question_id,                                                           -- Stable identifier.
  t.question,                                                                   -- The open question.
  t.context,                                                                    -- Why it is open / what it affects.
  t.resolution,                                                                 -- The decision, once made.
  t.is_resolved,                                                                -- TRUE when decided.
  calc_open_questions_name(t.open_question_id) AS name,                         -- Display label.
  calc_open_questions_relative_path(t.open_question_id) AS relative_path        -- Path to this OpenQuestions entry: /admin/open-questions/<id>.
FROM open_questions t;

-- ----------------------------------------------------------------------------
-- vw_non_goals: Explicit out-of-scope statements — the positive twin of the anti-hallucination ledger. Stops scope creep.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_non_goals CASCADE;
CREATE VIEW vw_non_goals WITH (security_invoker = ON) AS
SELECT
  t.non_goal_id,                                                                -- Stable identifier.
  t.statement,                                                                  -- What we are deliberately NOT doing.
  t.why_excluded,                                                               -- Why it is off the keystone path / out of scope.
  calc_non_goals_name(t.non_goal_id) AS name,                                   -- Display label.
  calc_non_goals_relative_path(t.non_goal_id) AS relative_path                  -- Path to this NonGoals entry: /admin/non-goals/<id>.
FROM non_goals t;

-- ----------------------------------------------------------------------------
-- vw_glossary_terms: Vocabulary coined in the gauntlet conversation, so the framing is shared and stable across sessions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_glossary_terms CASCADE;
CREATE VIEW vw_glossary_terms WITH (security_invoker = ON) AS
SELECT
  t.glossary_term_id,                                                           -- Stable identifier.
  t.term,                                                                       -- The term.
  t.definition,                                                                 -- What it means here.
  calc_glossary_terms_name(t.glossary_term_id) AS name,                         -- Display label.
  calc_glossary_terms_relative_path(t.glossary_term_id) AS relative_path        -- Path to this GlossaryTerms entry: /admin/glossary/<id>.
FROM glossary_terms t;

-- ----------------------------------------------------------------------------
-- vw_leopold_loops: The ordered Leopold loops that build this platform, as data. The derived plan (LEOPOLD_LOOPs.md, via json-hbars-transform) is generated from these rows; completed ([DONE]) loops are pruned at publish so only current/roadmap work shows in the plan.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_leopold_loops CASCADE;
CREATE VIEW vw_leopold_loops WITH (security_invoker = ON) AS
SELECT
  t.leopold_loop_id,                                                            -- Stable identifier.
  t.loop_number,                                                                -- Display number (0, 0.5, 1...).
  t.title,                                                                      -- Loop title.
  t.goal,                                                                       -- The one coherent rule-change / outcome.
  t.status,                                                                     -- done | next | planned | backlog (the raw input that drives Completedness).
  t.rule_commit_msg,                                                            -- The rule commit message (or "none — app-only loop").
  t.state_commit_msg,                                                           -- The state commit message.
  t.sort_order,                                                                 -- Ordering within the plan.
  calc_leopold_loops_name(t.leopold_loop_id) AS name,                           -- Display label.
  calc_leopold_loops_relative_path(t.leopold_loop_id) AS relative_path,         -- Path to this LeopoldLoops entry: /admin/leopold-loops/<id>.
  calc_leopold_loops_completedness(t.leopold_loop_id) AS completedness,         -- Normalized status used by the derived plan to decide placement.
  calc_leopold_loops_is_in_current_plan(t.leopold_loop_id) AS is_in_current_plan,-- TRUE for the current "next" loop and anything still planned/backlog (not done).
  t.status_badge,                                                               -- Display badge for the derived plan, e.g. [DONE] / [NEXT] / [PLANNED] / [BACKLOG].
  t.status_line                                                                 -- Extra plan line: commit messages for done/next loops; empty otherwise.
FROM leopold_loops t;

-- ----------------------------------------------------------------------------
-- vw_routing_and_navigation: Role-based navigation: open-ended parent->child->leaf routes with computed paths. Each route has a template (/intake/case/:caseId); entities carry RelativePath that substitutes their own id/slug. Roles: admin, intake-clinician, diagnosing-doctor, external-llm.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_routing_and_navigation CASCADE;
CREATE VIEW vw_routing_and_navigation WITH (security_invoker = ON) AS
SELECT
  t.routing_and_navigation_id,                                                  -- Slug PK for this nav node, e.g. nav-intake-case.
  calc_routing_and_navigation_name(t.routing_and_navigation_id) AS name,        -- Slug of the display name.
  t.display_name,                                                               -- Human-readable nav label.
  t.route,                                                                      -- URL template, role/workflow-prefixed with :params, e.g. /intake/case/:caseId.
  t.description,                                                                -- What this route shows.
  t.sort_order,                                                                 -- Display order within its nav level.
  t.parent_route_key,                                                           -- RouteKey of the parent nav node (empty for top-level). Self-referential recursion.
  t.route_key,                                                                  -- Stable dot-delimited slug, e.g. diagnosis.case.mechanism.
  t.nav_level,                                                                  -- Hierarchy level: top / sub / leaf.
  t.role_visibility,                                                            -- CSV of roles that can see this nav item: admin,intake-clinician,diagnosing-doctor,external-llm.
  t.primary_table,                                                              -- Backing table name.
  t.primary_view,                                                               -- Backing vw_* view.
  t.icon_hint,                                                                  -- Optional icon name for the UI.
  t.is_dynamic,                                                                 -- True if the route template contains :params.
  t.pin_to_top,                                                                 -- Pin to the top of its nav level, before SortOrder.
  t.admin_crud,                                                                 -- Admin CRUD grant for this route (contains C/R/U/D). Empty = no access.
  t.intake_clinician_crud,                                                      -- IntakeClinician CRUD grant for this route (contains C/R/U/D). Empty = no access.
  t.diagnosing_doctor_crud,                                                     -- DiagnosingDoctor CRUD grant for this route (contains C/R/U/D). Empty = no access.
  t.external_llm_crud,                                                          -- ExternalLlm CRUD grant for this route (contains C/R/U/D). Empty = no access.
  calc_routing_and_navigation_admin_can_create(t.routing_and_navigation_id) AS admin_can_create,-- Derived: AdminCRUD contains 'C'.
  calc_routing_and_navigation_admin_can_read(t.routing_and_navigation_id) AS admin_can_read,-- Derived: AdminCRUD contains 'R'.
  calc_routing_and_navigation_admin_can_update(t.routing_and_navigation_id) AS admin_can_update,-- Derived: AdminCRUD contains 'U'.
  calc_routing_and_navigation_admin_can_delete(t.routing_and_navigation_id) AS admin_can_delete,-- Derived: AdminCRUD contains 'D'.
  calc_routing_and_navigation_intake_clinician_can_create(t.routing_and_navigation_id) AS intake_clinician_can_create,-- Derived: IntakeClinicianCRUD contains 'C'.
  calc_routing_and_navigation_intake_clinician_can_read(t.routing_and_navigation_id) AS intake_clinician_can_read,-- Derived: IntakeClinicianCRUD contains 'R'.
  calc_routing_and_navigation_intake_clinician_can_update(t.routing_and_navigation_id) AS intake_clinician_can_update,-- Derived: IntakeClinicianCRUD contains 'U'.
  calc_routing_and_navigation_intake_clinician_can_delete(t.routing_and_navigation_id) AS intake_clinician_can_delete,-- Derived: IntakeClinicianCRUD contains 'D'.
  calc_routing_and_navigation_diagnosing_doctor_can_create(t.routing_and_navigation_id) AS diagnosing_doctor_can_create,-- Derived: DiagnosingDoctorCRUD contains 'C'.
  calc_routing_and_navigation_diagnosing_doctor_can_read(t.routing_and_navigation_id) AS diagnosing_doctor_can_read,-- Derived: DiagnosingDoctorCRUD contains 'R'.
  calc_routing_and_navigation_diagnosing_doctor_can_update(t.routing_and_navigation_id) AS diagnosing_doctor_can_update,-- Derived: DiagnosingDoctorCRUD contains 'U'.
  calc_routing_and_navigation_diagnosing_doctor_can_delete(t.routing_and_navigation_id) AS diagnosing_doctor_can_delete,-- Derived: DiagnosingDoctorCRUD contains 'D'.
  calc_routing_and_navigation_external_llm_can_create(t.routing_and_navigation_id) AS external_llm_can_create,-- Derived: ExternalLlmCRUD contains 'C'.
  calc_routing_and_navigation_external_llm_can_read(t.routing_and_navigation_id) AS external_llm_can_read,-- Derived: ExternalLlmCRUD contains 'R'.
  calc_routing_and_navigation_external_llm_can_update(t.routing_and_navigation_id) AS external_llm_can_update,-- Derived: ExternalLlmCRUD contains 'U'.
  calc_routing_and_navigation_external_llm_can_delete(t.routing_and_navigation_id) AS external_llm_can_delete,-- Derived: ExternalLlmCRUD contains 'D'.
  calc_routing_and_navigation_depth(t.routing_and_navigation_id) AS depth,      -- Nesting depth: 0 = top-level; otherwise number of dot-segments in RouteKey.
  calc_routing_and_navigation_full_path(t.routing_and_navigation_id) AS full_path,-- Canonical role-agnostic URL path (equals Route).
  calc_routing_and_navigation_handler_base_name(t.routing_and_navigation_id) AS handler_base_name,-- Space-delimited form of RouteKey; client PascalCases + prefixes role to derive a handler component.
  calc_routing_and_navigation_relative_path(t.routing_and_navigation_id) AS relative_path,-- Path to this routing node's own admin page.
  t.created_at,                                                                 -- Audit: when first inserted.
  t.created_by,                                                                 -- Audit: owner who created it.
  t.modified_at,                                                                -- Audit: when last written.
  t.modified_by,                                                                -- Audit: who last wrote it.
  t.modified_by_model                                                           -- Audit: AI model credited on last save, if any.
FROM routing_and_navigation t;

-- ----------------------------------------------------------------------------
-- vw_state_machines: State-machine definitions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_state_machines CASCADE;
CREATE VIEW vw_state_machines WITH (security_invoker = ON) AS
SELECT
  t.state_machine_id,                                                           -- Slug PK, e.g. diagnosis-lifecycle.
  calc_state_machines_name(t.state_machine_id) AS name,                         -- Echoes StateMachineId.
  calc_state_machines_relative_path(t.state_machine_id) AS relative_path,       -- Path to this machine's page.
  t.title,                                                                      -- Human-readable machine title.
  t.description,                                                                -- What this machine governs and its high-level flow.
  t.subject_table_name,                                                         -- Entity table this machine governs (convention string, NOT a FK).
  t.subject_state_column,                                                       -- Raw/derived column on the subject holding its current state.
  t.machine_states,                                                             -- Reverse: legal states of this machine.
  t.state_transition_rules,                                                     -- Reverse: legal edges of this machine.
  t.state_transitions,                                                          -- Reverse: instance transition log rows.
  calc_state_machines_state_count(t.state_machine_id) AS state_count,           -- Count of MachineStates in this machine.
  calc_state_machines_transition_rule_count(t.state_machine_id) AS transition_rule_count,-- Count of StateTransitionRules in this machine.
  t.created_at,                                                                 -- Audit: when first inserted.
  t.created_by,                                                                 -- Audit: owner who created it.
  t.modified_at,                                                                -- Audit: when last written.
  t.modified_by,                                                                -- Audit: who last wrote it.
  t.modified_by_model                                                           -- Audit: AI model credited on last save, if any.
FROM state_machines t;

-- ----------------------------------------------------------------------------
-- vw_machine_states: Legal states of each machine.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_machine_states CASCADE;
CREATE VIEW vw_machine_states WITH (security_invoker = ON) AS
SELECT
  t.machine_state_id,                                                           -- Slug PK, e.g. diagnosis-lifecycle--intake.
  calc_machine_states_name(t.machine_state_id) AS name,                         -- Echoes MachineStateId.
  calc_machine_states_relative_path(t.machine_state_id) AS relative_path,       -- Path to this state's page.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.state_key,                                                                  -- Bare value as stored/derived in the subject's current-state column.
  t.title,                                                                      -- Human-readable state title.
  t.order_index,                                                                -- Sort order of this state within the machine.
  t.is_initial,                                                                 -- TRUE if this is the machine's entry state.
  t.is_terminal,                                                                -- TRUE if this is a terminal/end state.
  t.from_transition_rules,                                                      -- Reverse: rules whose FromState is this state.
  t.to_transition_rules,                                                        -- Reverse: rules whose ToState is this state.
  t.created_at,                                                                 -- Audit: when first inserted.
  t.created_by,                                                                 -- Audit: owner who created it.
  t.modified_at,                                                                -- Audit: when last written.
  t.modified_by,                                                                -- Audit: who last wrote it.
  t.modified_by_model,                                                          -- Audit: AI model credited on last save, if any.
  calc_machine_states_reachable_state_count(t.machine_state_id) AS reachable_state_count-- Number of states reachable FROM this state via the transitive closure of the transition edges (rollup over vw_state_transition_rules_closure where from_id = this state). This is a graph-reachability fact the linear severity rank CANNOT reproduce: both Quiescent (the remission sink) and BiopsyIndicated (the terminal progression state) have 0 reachable-ahead, though they sit at opposite ends of the order — the count is non-monotonic in OrderIndex because the machine BRANCHES (remission). The closure is load-bearing here: delete it and this field is uncomputable.
FROM machine_states t;

-- ----------------------------------------------------------------------------
-- vw_state_transition_rules: Legal edges (guards) of each machine.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_state_transition_rules CASCADE;
CREATE VIEW vw_state_transition_rules WITH (security_invoker = ON) AS
SELECT
  t.state_transition_rule_id,                                                   -- Slug PK.
  calc_state_transition_rules_name(t.state_transition_rule_id) AS name,         -- Echoes StateTransitionRuleId.
  calc_state_transition_rules_relative_path(t.state_transition_rule_id) AS relative_path,-- Path to this rule's page.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.from_state,                                                                 -- FK -> MachineStates.MachineStateId.
  t.to_state,                                                                   -- FK -> MachineStates.MachineStateId.
  t.guard_description,                                                          -- Prose guard citing the DAG conditions. Does NOT reimplement rule logic.
  t.rule_refs,                                                                  -- CSV of business-rule / gate codes the guard enforces.
  t.trigger_endpoint,                                                           -- API endpoint whose action fires this transition.
  t.triggered_by_role,                                                          -- Role that fires this edge. Enum: system / intake-clinician / diagnosing-doctor / external-llm.
  calc_state_transition_rules_from_state_key(t.state_transition_rule_id) AS from_state_key,-- Lookup: FromState.StateKey.
  calc_state_transition_rules_to_state_key(t.state_transition_rule_id) AS to_state_key,-- Lookup: ToState.StateKey.
  calc_state_transition_rules_is_forward_edge(t.state_transition_rule_id) AS is_forward_edge,-- TRUE when the edge advances to a different state (all edges here).
  t.created_at,                                                                 -- Audit: when first inserted.
  t.created_by,                                                                 -- Audit: owner who created it.
  t.modified_at,                                                                -- Audit: when last written.
  t.modified_by,                                                                -- Audit: who last wrote it.
  t.modified_by_model                                                           -- Audit: AI model credited on last save, if any.
FROM state_transition_rules t;

-- ----------------------------------------------------------------------------
-- vw_state_transitions: Instance-level transition log (the witnessed history).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_state_transitions CASCADE;
CREATE VIEW vw_state_transitions WITH (security_invoker = ON) AS
SELECT
  t.state_transition_id,                                                        -- Slug PK.
  calc_state_transitions_name(t.state_transition_id) AS name,                   -- Echoes StateTransitionId.
  calc_state_transitions_relative_path(t.state_transition_id) AS relative_path, -- Path to this transition's page.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.subject_table_name,                                                         -- Polymorphic: name of the subject's table (raw string, NOT a FK).
  t.subject_id,                                                                 -- Polymorphic: id of the subject row (raw string, NOT a FK).
  t.from_state_key,                                                             -- Bare from-state value. Null on the initial creation transition.
  t.to_state_key,                                                               -- Bare to-state value.
  t.transition_at,                                                              -- When the transition occurred.
  t.triggered_by_role,                                                          -- Role that fired this transition.
  t.reason,                                                                     -- Why the transition happened (free text).
  calc_state_transitions_is_forward(t.state_transition_id) AS is_forward,       -- TRUE when ToStateKey is not the machine's initial state.
  t.created_at,                                                                 -- Audit: when first inserted.
  t.created_by,                                                                 -- Audit: owner who created it.
  t.modified_at,                                                                -- Audit: when last written.
  t.modified_by,                                                                -- Audit: who last wrote it.
  t.modified_by_model                                                           -- Audit: AI model credited on last save, if any.
FROM state_transitions t;

-- ----------------------------------------------------------------------------
-- vw_subject_state_instances: Per-subject state occupancy records; current state has blank ExitedAt.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_subject_state_instances CASCADE;
CREATE VIEW vw_subject_state_instances WITH (security_invoker = ON) AS
SELECT
  t.subject_state_instance_id,                                                  -- PK: ssi-{subject-id}-{state-key}-{seq}.
  calc_subject_state_instances_name(t.subject_state_instance_id) AS name,       -- Echoes SubjectStateInstanceId.
  calc_subject_state_instances_relative_path(t.subject_state_instance_id) AS relative_path,-- Path to this occupancy record.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.subject_table_name,                                                         -- Polymorphic table name.
  t.subject_id,                                                                 -- Polymorphic PK of the subject row.
  t.state_key,                                                                  -- The machine state entered by this occupancy record.
  t.entered_at,                                                                 -- Timestamp when this state was entered.
  t.exited_at,                                                                  -- Timestamp when the subject left this state. NULL while current.
  t.sequence_index,                                                             -- 1-based position on this subject's path through the machine.
  t.prior_instance,                                                             -- Self-FK: previous occupancy in this subject's chain. NULL for initial.
  t.entered_via_transition,                                                     -- FK -> StateTransitions: the edge event that created this occupancy.
  calc_subject_state_instances_is_current(t.subject_state_instance_id) AS is_current,-- TRUE when ExitedAt IS NULL — the subject's active state.
  calc_subject_state_instances_has_complete_lineage(t.subject_state_instance_id) AS has_complete_lineage,-- TRUE when lineage walks back to SequenceIndex 1.
  t.created_at,                                                                 -- Audit: when first inserted.
  t.created_by,                                                                 -- Audit: owner who created it.
  t.modified_at,                                                                -- Audit: when last written.
  t.modified_by,                                                                -- Audit: who last wrote it.
  t.modified_by_model,                                                          -- Audit: AI model credited on last save, if any.
  t.dwell_days,                                                                 -- Bitemporal dwell: days the subject occupied this state (transparent raw value; transpiler lacks date-diff). Witnessed + editable, like any leaf.
  calc_subject_state_instances_is_long_dwell(t.subject_state_instance_id) AS is_long_dwell-- TRUE when DwellDays >= 90 (a season).
FROM subject_state_instances t;

-- ----------------------------------------------------------------------------
-- vw_disease_domain_concepts: v2 vocabulary completeness: every disease-domain concept the v1 audit named, with its modeling status and the challenge-stressor TYPE it instantiates. Makes the coverage claim checkable by grep, not by trust.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_disease_domain_concepts CASCADE;
CREATE VIEW vw_disease_domain_concepts WITH (security_invoker = ON) AS
SELECT
  t.disease_domain_concept_id,                                                  -- Slug PK.
  t.concept_label,                                                              -- Human-readable concept name (the audit's missing word).
  t.related_disease,                                                            -- Disease this concept belongs to (SLE/RA/PsA/* for cross-cutting). Convention string, not a FK.
  t.modeling_status,                                                            -- deep-dag | schema | vocabulary — how deeply v2 models this concept.
  t.definition,                                                                 -- What the concept is and how v2 represents it.
  t.challenge_stressor_type,                                                    -- Which TYPE of original-challenge stressor this concept instantiates (for the reconcile map).
  calc_disease_domain_concepts_name(t.disease_domain_concept_id) AS name,       -- Echoes ConceptLabel.
  calc_disease_domain_concepts_relative_path(t.disease_domain_concept_id) AS relative_path,-- Path to this concept's page.
  calc_disease_domain_concepts_is_deeply_modeled(t.disease_domain_concept_id) AS is_deeply_modeled,-- TRUE when this concept carries a witnessed inference DAG (status = deep-dag).
  calc_disease_domain_concepts_is_schema_modeled(t.disease_domain_concept_id) AS is_schema_modeled-- TRUE when first-class schema/data (deep-dag or schema).
FROM disease_domain_concepts t;

-- ----------------------------------------------------------------------------
-- vw_serology_observations: RAW longitudinal serology panels (the lab/LLM layer) + derived trend, SLEDAI sub-scores, and the disease state IMPLIED by each panel. The leaves that drive the lupus-nephritis progression machine.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_serology_observations CASCADE;
CREATE VIEW vw_serology_observations WITH (security_invoker = ON) AS
SELECT
  t.serology_observation_id,                                                    -- Slug PK: sero-{ind}-{seq}.
  t.individual,                                                                 -- FK -> Individuals.IndividualId.
  t.observed_at,                                                                -- Valid-time of this serology panel (RAW leaf).
  t.sequence_index,                                                             -- 1-based order within the individual's panel series (RAW).
  t.anti_ds_dna_iu,                                                             -- anti-dsDNA titre IU/mL (RAW lab).
  t.complement_c3,                                                              -- C3 mg/dL (RAW lab).
  t.complement_c4,                                                              -- C4 mg/dL (RAW lab).
  t.proteinuria_g_per_day,                                                      -- urine protein g/day (RAW lab).
  t.egfr_ml_min,                                                                -- eGFR mL/min (RAW lab).
  t.has_active_urinary_sediment,                                                -- active casts/hematuria (RAW observation).
  t.prior_observation,                                                          -- Self-FK -> the prior panel in this individual's series (seq-1). NULL for the first.
  calc_serology_observations_prior_anti_ds_dna_iu(t.serology_observation_id) AS prior_anti_ds_dna_iu,-- Prior panel's dsDNA via PriorObservation FK, for trend.
  calc_serology_observations_prior_c3(t.serology_observation_id) AS prior_c3,   -- Prior C3 via PriorObservation FK.
  calc_serology_observations_prior_c4(t.serology_observation_id) AS prior_c4,   -- Prior C4 via PriorObservation FK.
  calc_serology_observations_anti_ds_dna_trend(t.serology_observation_id) AS anti_ds_dna_trend,-- Rising/Falling/Stable vs prior panel (derived from raw).
  calc_serology_observations_complement_trend(t.serology_observation_id) AS complement_trend,-- Rising/Falling/Stable on C3+C4 vs prior (derived).
  calc_serology_observations_is_pre_nephritic_signature_panel(t.serology_observation_id) AS is_pre_nephritic_signature_panel,-- The pre-nephritic serology signature at THIS panel: rising anti-dsDNA + falling complement (the serological trajectory that precedes/tracks overt renal involvement). Emergent from the raw series, not a label anyone assigned. (Proteinuria is the OUTCOME the signature precedes, so it is deliberately NOT part of the signal.)
  calc_serology_observations_is_significant_proteinuria(t.serology_observation_id) AS is_significant_proteinuria,-- proteinuria >= 0.5 g/day.
  calc_serology_observations_is_nephrotic_range_proteinuria(t.serology_observation_id) AS is_nephrotic_range_proteinuria,-- proteinuria >= 3.0 g/day.
  calc_serology_observations_sledai_renal_points(t.serology_observation_id) AS sledai_renal_points,-- SLEDAI-style renal sub-score (0/4/8) from proteinuria + sediment.
  calc_serology_observations_sledai_serology_points(t.serology_observation_id) AS sledai_serology_points,-- SLEDAI-style serology sub-score (0/2/4) from low-complement + raised dsDNA.
  calc_serology_observations_sledai_score(t.serology_observation_id) AS sledai_score,-- Derived SLEDAI-style activity score = renal + serology points.
  calc_serology_observations_progression_state_key(t.serology_observation_id) AS progression_state_key,-- Disease state IMPLIED by THIS panel (derived purely from raw leaves).
  calc_serology_observations_progression_state_order(t.serology_observation_id) AS progression_state_order,-- Numeric severity order of THIS panel's implied state (0..5). Lets the individual's current state be a MAXIFS over panels (highest state reached).
  calc_serology_observations_name(t.serology_observation_id) AS name,           -- Echoes id.
  calc_serology_observations_relative_path(t.serology_observation_id) AS relative_path-- Path.
FROM serology_observations t;

-- ----------------------------------------------------------------------------
-- vw_therapy_options: Therapy lookup for the treatment-line-selection DAG (MMF/belimumab/anifrolumab/secukinumab).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_therapy_options CASCADE;
CREATE VIEW vw_therapy_options WITH (security_invoker = ON) AS
SELECT
  t.therapy_option_id,                                                          -- Slug PK.
  t.therapy_label,                                                              -- Therapy name.
  t.targets_pathway,                                                            -- Pathway this therapy targets (matches CausalMechanisms.TargetPathway).
  t.line_ordinal,                                                               -- Treatment-line ordinal (1=first-line/induction).
  t.preferred_when,                                                             -- Clinical context where preferred.
  calc_therapy_options_name(t.therapy_option_id) AS name,                       -- Echo.
  calc_therapy_options_relative_path(t.therapy_option_id) AS relative_path      -- Path.
FROM therapy_options t;

-- ----------------------------------------------------------------------------
-- vw_state_transition_rules_closure: Transitive closure of state-machine transitions (an owl:TransitiveProperty). The asserted FromState->ToState edges imply the full reachability ordering of each machine - including never-asserted long-range pairs such as PresymptomaticAutoimmunity -> BiopsyIndicated. Materialized by the transpiler as the cycle-safe recursive view vw_state_transition_rules_closure(from_id, to_id, hop_distance, is_inferred): asserted edges (hop 1) plus inferred reachability rows. The disease trajectory is derived from the transition topology, not hand-asserted.
-- Cycle-safe transitive closure of state_transition_rules(from_state -> to_state) [junction edge table].
-- Columns: from_id, to_id, hop_distance (shortest derivation), is_inferred
--          (TRUE iff no direct hop-1 edge asserts the pair).
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_state_transition_rules_closure CASCADE;
CREATE VIEW vw_state_transition_rules_closure WITH (security_invoker = ON) AS
WITH RECURSIVE edges AS (
    SELECT from_state AS from_id, to_state AS to_id
    FROM state_transition_rules
    -- Treat NULL and empty-string FKs as 'no edge' (the transpiler stores absent
    -- relationship values as '' rather than NULL, so both must be excluded).
    WHERE from_state IS NOT NULL AND from_state <> '' AND to_state IS NOT NULL AND to_state <> ''
),
closure AS (
    -- Base: the directly-asserted edges (hop 1).
    SELECT
        e.from_id,
        e.to_id,
        1 AS hop_distance,
        ARRAY[e.from_id, e.to_id] AS path
    FROM edges e
    UNION ALL
    -- Step: extend each path by one asserted edge, skipping nodes already on the
    -- path so cyclic edge sets terminate (cycle-safe).
    SELECT
        cl.from_id,
        e.to_id,
        cl.hop_distance + 1,
        cl.path || e.to_id
    FROM closure cl
    JOIN edges e ON e.from_id = cl.to_id
    WHERE NOT (e.to_id = ANY(cl.path))
)
SELECT
    cl.from_id,
    cl.to_id,
    MIN(cl.hop_distance) AS hop_distance,
    NOT EXISTS (
        SELECT 1 FROM edges e2
        WHERE e2.from_id = cl.from_id AND e2.to_id = cl.to_id
    ) AS is_inferred
FROM closure cl
GROUP BY cl.from_id, cl.to_id;


